const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const auctionId = String(body.auction_id || '').trim();
const handle    = String(body.bidder_handle || '').trim();
const platform  = String(body.platform || '').trim().toLowerCase();
const rawInput  = (body.raw_input == null ? '' : String(body.raw_input)).trim();
const amountIn  = body.amount_cents != null ? parseInt(body.amount_cents, 10) : null;

if (!auctionId) return { json: { ok: false, status: 400, error: 'auction_id required' } };
if (!handle)    return { json: { ok: false, status: 400, error: 'bidder_handle required (e.g. \"@username\")' } };
if (!platform)  return { json: { ok: false, status: 400, error: 'platform required' } };

const allowedPlatforms = ['tiktok','tiktok_comment','facebook','facebook_comment','instagram','instagram_dm','youtube','sms','whatsapp','web_form','manual'];
if (allowedPlatforms.indexOf(platform) === -1) {
  return { json: { ok: false, status: 400, error: 'invalid platform; must be one of: ' + allowedPlatforms.join(', ') } };
}

// Amount: either from amount_cents directly OR parsed from raw_input.
let amountCents = null;
if (amountIn != null && !isNaN(amountIn) && amountIn > 0) {
  amountCents = amountIn;
} else if (rawInput) {
  const m = rawInput.replace(/[,]/g, '').match(/(\$\s*)?(\d+(?:\.\d{1,2})?)/);
  if (m) {
    const d = parseFloat(m[2]);
    if (!isNaN(d) && d > 0) amountCents = Math.round(d * 100);
  }
}
if (amountCents == null) return { json: { ok: false, status: 400, error: 'Could not determine bid amount — provide amount_cents OR raw_input with a number like "BID 50"' } };

// Identity hash: SHA-256 of (platform + ':' + lowercased handle).
// Match the bidder_identity_hash convention used by the existing
// bid-parser flow so an auto-registered bidder is shared across both
// entry paths.
const crypto = require('crypto');
const normHandle = handle.toLowerCase().replace(/^@+/, '');
const identityHash = crypto.createHash('sha256').update(platform + ':' + normHandle).digest('hex');

return { json: {
  token: token,
  auction_id:     auctionId,
  bidder_handle:  handle,
  bidder_norm:    normHandle,
  platform:       platform,
  identity_hash:  identityHash,
  raw_input:      rawInput,
  amount_cents:   amountCents
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract + Hash').item.json;
return { json: Object.assign({ ok: true }, x) };

// Resolve bidder: either an existing row or an INSERT.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const found = allOf('Lookup Bidder');
const x = $('Check Admin').item.json;
if (found.length > 0) {
  if (found[0].banned_at) {
    return { json: { ok: false, status: 403, error: 'Bidder is banned: ' + (found[0].display_name || x.bidder_handle) } };
  }
  return { json: { _existing: true, bidder_trust_id: found[0].id, trust_tier: found[0].trust_tier, display_name: found[0].display_name } };
}
// New bidder — return the body to INSERT.
return { json: {
  _existing: false,
  insert_body: {
    bidder_identity_hash: x.identity_hash,
    display_name:         x.bidder_handle,
    platform:             x.platform,
    trust_tier:           'tier_0',
    max_bid_cents:        0
  }
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
// Resolve the bidder_trust_id from whichever path ran (existing or newly inserted).
let bidderTrustId;
let bidderDisplay;
try {
  const decided = $('Decide Bidder').first().json;
  if (decided._existing) {
    bidderTrustId = decided.bidder_trust_id;
    bidderDisplay = decided.display_name;
  } else {
    const inserted = allOf('Insert Bidder');
    if (inserted.length === 0) return { json: { ok: false, status: 500, error: 'Bidder insert returned no row' } };
    bidderTrustId = inserted[0].id;
    bidderDisplay = inserted[0].display_name;
  }
} catch (e) {
  return { json: { ok: false, status: 500, error: 'Bidder resolution error: ' + e.message } };
}

const auctions = allOf('Fetch Auction');
if (auctions.length === 0) return { json: { ok: false, status: 404, error: 'Auction not found' } };
const a = auctions[0];
if (a.status !== 'open' && a.status !== 'extended') {
  return { json: { ok: false, status: 409, error: 'Auction is not accepting bids (status=' + a.status + ')' } };
}
const x = $('Check Admin').item.json;
const currentHigh  = a.current_high_bid_cents || 0;
const minIncrement = a.min_increment_cents || 100;
const minimumNext  = currentHigh + minIncrement;
if (x.amount_cents < minimumNext) {
  return { json: { ok: false, status: 422, error: 'Bid too low. Current high $' + (currentHigh/100).toFixed(2) + '; minimum next bid $' + (minimumNext/100).toFixed(2) + '. Your bid $' + (x.amount_cents/100).toFixed(2) } };
}
return { json: {
  ok: true,
  bidder_trust_id: bidderTrustId,
  bidder_display:  bidderDisplay,
  bid_body: {
    auction_id:        x.auction_id,
    bidder_trust_id:   bidderTrustId,
    amount_cents:      x.amount_cents,
    source_platform:   x.platform === 'manual' ? 'manual' : x.platform,
    raw_input:         x.raw_input || ('manual entry: ' + x.bidder_handle + ' $' + (x.amount_cents/100).toFixed(2)),
    status:            'active'
  },
  previous_high_bid_id: a.current_high_bid_id || null,
  auction_id:           a.id
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const inserted = allOf('Insert Bid');
if (inserted.length === 0) return { json: { ok: false, status: 500, error: 'Bid insert returned no row' } };
const newBid = inserted[0];
const v = $('Validate + Build Bid').first().json;
const now = new Date().toISOString();
return { json: {
  ok: true,
  bid: newBid,
  bidder_display: v.bidder_display,
  prev_high_bid_id: v.previous_high_bid_id,
  auction_patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/auctions?id=eq.' + newBid.auction_id,
  auction_patch_body: { current_high_bid_cents: newBid.amount_cents, current_high_bid_id: newBid.id, updated_at: now },
  outbid_patch_url:  v.previous_high_bid_id ? ('https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/auction_bids?id=eq.' + v.previous_high_bid_id) : null,
  outbid_patch_body: { status: 'outbid', outbid_at: now }
} };

const v = $('Build Updates').first().json;
return { json: {
  ok: true,
  bid_id:          v.bid.id,
  auction_id:      v.bid.auction_id,
  amount_cents:    v.bid.amount_cents,
  amount_display:  '$' + (v.bid.amount_cents/100).toFixed(2),
  bidder_display:  v.bidder_display,
  previous_outbid_id: v.prev_high_bid_id || null
} };
